#include <iostream>
#include <cassert>
#include <climits>
using namespace std;

int findMax(int num1, int num2);

int main() {
    assert(findMax(5, 3) == 5);
    assert(findMax(INT_MAX, INT_MAX-1) == INT_MAX);
    assert(findMax(INT_MIN, INT_MIN+1) == INT_MIN+1);
    assert(findMax(0, 7) == 7);
    assert(findMax(100, 100) == 100);
    cout << "All tests passed!" << endl;
    return 0;
